import re
from typing import Any
from pymongo import MongoClient
from pymongo.collection import Collection


# ---------------------------------------------------------------------------
# Safe filter expression parser
# ---------------------------------------------------------------------------

ALLOWED_OPERATORS = {
    "eq": "$eq",
    "ne": "$ne",
    "gt": "$gt",
    "gte": "$gte",
    "lt": "$lt",
    "lte": "$lte",
    "in": "$in",
    "nin": "$nin",
    "regex": "$regex",
    "exists": "$exists",
    "type": "$type",
}

ALLOWED_LOGICAL = {"and": "$and", "or": "$or", "nor": "$nor"}

# Only allow field names that look like valid, safe identifiers
SAFE_FIELD_RE = re.compile(r"^[a-zA-Z_][a-zA-Z0-9_.]*$")


def _validate_field_name(field: str) -> str:
    """Reject field names that could be used for injection (e.g. starting with $)."""
    if not SAFE_FIELD_RE.match(field):
        raise ValueError(f"Invalid field name: {field!r}")
    if field.startswith("$"):
        raise ValueError(f"Field names must not start with '$': {field!r}")
    return field


def _coerce_value(value: Any, expected_type: str | None = None) -> Any:
    """Coerce a user-supplied value to a safe Python type."""
    if isinstance(value, (int, float, bool, type(None))):
        return value
    if isinstance(value, str):
        return value
    if isinstance(value, list):
        return [_coerce_value(v) for v in value]
    raise ValueError(f"Unsupported value type: {type(value)}")


def build_safe_query(filter_spec: dict | list) -> dict:
    """
    Convert a user-friendly filter specification into a safe MongoDB query.

    Accepted format (JSON-serialisable dict/list):

    Single condition:
        {"field": "age", "op": "gte", "value": 21}

    Logical combination:
        {
            "logic": "and",
            "conditions": [
                {"field": "age", "op": "gte", "value": 21},
                {"field": "status", "op": "eq", "value": "active"}
            ]
        }

    Nested logic:
        {
            "logic": "or",
            "conditions": [
                {
                    "logic": "and",
                    "conditions": [
                        {"field": "age", "op": "gte", "value": 21},
                        {"field": "role", "op": "eq", "value": "admin"}
                    ]
                },
                {"field": "superuser", "op": "eq", "value": true}
            ]
        }
    """
    if isinstance(filter_spec, list):
        # Treat a bare list as an implicit $and
        return {"$and": [build_safe_query(cond) for cond in filter_spec]}

    if not isinstance(filter_spec, dict):
        raise ValueError("Filter spec must be a dict or list of dicts")

    # --- Logical operator node ---
    if "logic" in filter_spec:
        logic_key = filter_spec["logic"].lower()
        if logic_key not in ALLOWED_LOGICAL:
            raise ValueError(
                f"Unsupported logical operator: {logic_key!r}. "
                f"Allowed: {list(ALLOWED_LOGICAL)}"
            )
        conditions = filter_spec.get("conditions")
        if not isinstance(conditions, list) or len(conditions) == 0:
            raise ValueError("'conditions' must be a non-empty list")
        mongo_op = ALLOWED_LOGICAL[logic_key]
        return {mongo_op: [build_safe_query(c) for c in conditions]}

    # --- Leaf condition node ---
    field = _validate_field_name(filter_spec["field"])
    op = filter_spec.get("op", "eq").lower()

    if op not in ALLOWED_OPERATORS:
        raise ValueError(
            f"Unsupported operator: {op!r}. Allowed: {list(ALLOWED_OPERATORS)}"
        )

    value = _coerce_value(filter_spec["value"])
    mongo_op = ALLOWED_OPERATORS[op]

    # Special handling for $regex — ensure value is a string
    if mongo_op == "$regex":
        if not isinstance(value, str):
            raise ValueError("Regex value must be a string")
        options = filter_spec.get("options", "")
        if not isinstance(options, str) or not re.match(r"^[imsx]*$", options):
            raise ValueError("Invalid regex options")
        return {field: {"$regex": value, "$options": options}}

    return {field: {mongo_op: value}}


# ---------------------------------------------------------------------------
# MongoDB filtering service
# ---------------------------------------------------------------------------

class MongoFilterService:
    """Advanced data filtering service backed by MongoDB."""

    def __init__(
        self,
        connection_string: str = "mongodb://localhost:27017",
        database: str = "mydb",
    ):
        self.client = MongoClient(connection_string)
        self.db = self.client[database]

    def get_collection(self, name: str) -> Collection:
        _validate_field_name(name)  # reuse validation for collection names
        return self.db[name]

    def filter_documents(
        self,
        collection_name: str,
        filter_spec: dict | list,
        projection: dict | None = None,
        sort: list[tuple[str, int]] | None = None,
        limit: int = 100,
        skip: int = 0,
    ) -> list[dict]:
        """
        Execute a safe, parameterised query built from *filter_spec*.

        Parameters
        ----------
        collection_name : str
        filter_spec : dict or list
            User-supplied filter (see ``build_safe_query`` for the format).
        projection : dict, optional
            MongoDB projection document.
        sort : list of (field, direction) tuples, optional
        limit : int
            Max documents to return (capped at 1000).
        skip : int

        Returns
        -------
        list of dict
        """
        query = build_safe_query(filter_spec)
        print(f"[DEBUG] Generated MongoDB query: {query}")

        collection = self.get_collection(collection_name)

        # Sanitise projection field names
        safe_projection = None
        if projection:
            safe_projection = {}
            for k, v in projection.items():
                _validate_field_name(k)
                if v not in (0, 1, True, False):
                    raise ValueError(f"Invalid projection value for {k!r}: {v!r}")
                safe_projection[k] = v

        # Sanitise sort
        safe_sort = None
        if sort:
            safe_sort = []
            for field, direction in sort:
                _validate_field_name(field)
                if direction not in (1, -1):
                    raise ValueError(f"Sort direction must be 1 or -1, got {direction}")
                safe_sort.append((field, direction))

        limit = min(max(1, limit), 1000)
        skip = max(0, skip)

        cursor = collection.find(query, safe_projection)
        if safe_sort:
            cursor = cursor.sort(safe_sort)
        cursor = cursor.skip(skip).limit(limit)

        return list(cursor)

    def count_documents(self, collection_name: str, filter_spec: dict | list) -> int:
        query = build_safe_query(filter_spec)
        collection = self.get_collection(collection_name)
        return collection.count_documents(query)

    def close(self):
        self.client.close()


